@page "/"

@inject IShipmentService ShipmentService

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Shipment Tracker</h1>
<p class="lead">Track and manage your shipments in real time.</p>

<div class="row mt-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track a Shipment</h5>
                <p class="card-text">Enter your tracking number to check the status of your delivery.</p>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="e.g. SHP-20260529-12345"
                           @bind="trackingInput" @bind:event="oninput"
                           @onkeydown="HandleTrackKeyDown" />
                    <a class="btn btn-primary" href="@($"track?number={Uri.EscapeDataString(trackingInput ?? "")}")"
                       @onclick="NavigateToTrack" @onclick:preventDefault>
                        Track
                    </a>
                </div>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <AuthorizeView>
            <Authorized>
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Dispatcher Dashboard</h5>
                        <p class="card-text">View all shipments, update statuses, and create new shipments.</p>
                        <a class="btn btn-outline-primary" href="shipments">Go to Dashboard</a>
                    </div>
                </div>
            </Authorized>
            <NotAuthorized>
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Dispatcher Access</h5>
                        <p class="card-text">Log in to manage shipments and update delivery statuses.</p>
                        <a class="btn btn-outline-primary" href="Account/Login">Log In</a>
                    </div>
                </div>
            </NotAuthorized>
        </AuthorizeView>
    </div>
</div>

@code {
    private string? trackingInput;

    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private void HandleTrackKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !string.IsNullOrWhiteSpace(trackingInput))
        {
            NavigateToTrack();
        }
    }

    private void NavigateToTrack()
    {
        if (!string.IsNullOrWhiteSpace(trackingInput))
        {
            Navigation.NavigateTo($"track?number={Uri.EscapeDataString(trackingInput)}");
        }
    }
}

@page "/shipments"
@attribute [Authorize]

@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="input-group" style="max-width: 400px;">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <button class="btn btn-success" @onclick="ShowCreateForm">
        + New Shipment
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Customer Email</label>
                    <input type="email" class="form-control" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary me-2" @onclick="CreateShipment" disabled="@isCreating">
                        @(isCreating ? "Creating..." : "Create Shipment")
                    </button>
                    <button class="btn btn-secondary" @onclick="CancelCreate">Cancel</button>
                </div>
            </div>
            @if (createError is not null)
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (filteredShipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Customer</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in filteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>@s.CustomerEmail</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                            {
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        @onchange="(e) => UpdateStatus(s, e)">
                                    <option value="" selected disabled>Update…</option>
                                    @foreach (var status in GetNextStatuses(s.Status))
                                    {
                                        <option value="@((int)status)">@status</option>
                                    }
                                </select>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string? filterText;
    private bool showCreateForm;
    private bool isCreating;
    private string? createError;
    private CreateShipmentRequest newShipment = new();

    private List<ShipmentDto> filteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .ToList() ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreateForm = true;

    private void CancelCreate()
    {
        showCreateForm = false;
        newShipment = new();
        createError = null;
    }

    private async Task CreateShipment()
    {
        createError = null;

        if (string.IsNullOrWhiteSpace(newShipment.Origin) || string.IsNullOrWhiteSpace(newShipment.Destination))
        {
            createError = "Origin and Destination are required.";
            return;
        }

        isCreating = true;
        try
        {
            var created = await ShipmentService.CreateShipmentAsync(newShipment);
            shipments?.Insert(0, created);
            showCreateForm = false;
            newShipment = new();
        }
        catch (Exception ex)
        {
            createError = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            isCreating = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && int.TryParse(val, out var statusInt))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(
                shipment.Id, new UpdateShipmentStatusRequest { NewStatus = (ShipmentStatus)statusInt });
            if (updated is not null)
            {
                var index = shipments!.FindIndex(s => s.Id == shipment.Id);
                if (index >= 0)
                    shipments[index] = updated;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static ShipmentStatus[] GetNextStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Cancelled],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Cancelled],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Cancelled],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Cancelled],
        _ => []
    };
}

