toolArgs.new_str:
// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
var shipmentApi = app.MapGroup("api/shipments");

shipmentApi.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()))
    .RequireAuthorization();

shipmentApi.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
});

shipmentApi.MapPost("/", async (CreateShipmentRequest request, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(request);
    return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
}).RequireAuthorization();

shipmentApi.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, IShipmentService service) =>
{
    var updated = await service.UpdateShipmentStatusAsync(id, request);
    return updated is null ? Results.NotFound() : Results.Ok(updated);
}).RequireAuthorization();

// Ensure database is created
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    db.Database.Migrate();
}

app.Run();

